from typing import Union, Optional, Any


class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None

    def __init__(self, type: str, **kwargs):
        self.type = type
        for key, value in kwargs.items():
            setattr(self, key, value)

    def __repr__(self):
        if self.type == "number":
            return f"Number({self.value})"
        elif self.type == "binop":
            return f"BinOp({self.op}, {self.left}, {self.right})"
        elif self.type == "unary":
            return f"UnaryOp({self.op}, {self.operand})"
        else:
            return f"ASTNode({self.type})"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty expression")

    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c in "()+-*/":
            tokens.append(c)
            i += 1
        elif c.isdigit() or c == ".":
            start = i
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                i += 1
            num_str = expression[start:i]
            try:
                num = float(num_str)
            except ValueError:
                raise ValueError(f"Invalid number format: {num_str}")
            tokens.append(num)
        else:
            raise ValueError(f"Invalid token: {c}")

    if not tokens:
        raise ValueError("Empty expression")

    return parse_expression(tokens)


def parse_expression(tokens: list) -> ASTNode:
    return parse_binary_expression(tokens, 0)


def parse_binary_expression(tokens: list, precedence: int) -> ASTNode:
    left = parse_primary(tokens)

    while tokens and isinstance(tokens[0], str) and is_binary_operator(tokens[0]):
        op = tokens[0]
        op_precedence = get_operator_precedence(op)

        if op_precedence < precedence:
            break

        tokens.pop(0)
        right = parse_binary_expression(tokens, op_precedence + 1)

        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def parse_primary(tokens: list) -> ASTNode:
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens[0]

    if isinstance(token, float):
        tokens.pop(0)
        return ASTNode("number", value=token)

    if token == "(":
        tokens.pop(0)
        expr = parse_expression(tokens)
        if not tokens or tokens[0] != ")":
            raise ValueError("Unmatched parenthesis")
        tokens.pop(0)
        return expr

    if token == "-":
        tokens.pop(0)
        operand = parse_primary(tokens)
        return ASTNode("unary", op="-", operand=operand)

    if token == "+":
        tokens.pop(0)
        return parse_primary(tokens)

    raise ValueError(f"Unexpected token: {token}")


def is_binary_operator(token: str) -> bool:
    return token in "+-*/"


def get_operator_precedence(op: str) -> int:
    if op in "*/":
        return 2
    elif op in "+-":
        return 1
    else:
        return 0


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value
    elif node.type == "binop":
        if node.left is None or node.right is None or node.op is None:
            raise ValueError("Binary operator node is missing required attributes")
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown binary operator: {node.op}")
    elif node.type == "unary":
        if node.operand is None or node.op is None:
            raise ValueError("Unary operator node is missing required attributes")
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        elif node.op == "+":
            return operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")
